  ('aboriginal-7c9828ae-moex-00048', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '依憲法第8條第1項之規定，司法或警察機關依法定程序，得逮捕拘禁人民。關於本項規定之司法機關與警 察機關，下列敘述何者正確？', '["司法機關包括檢察機關，警察機關不限於組織法上之形式意義警察機關", "司法機關包括檢察機關，警察機關限於組織法上之形式意義警察機關", "司法機關不包括檢察機關，警察機關不限於組織法上之形式意義警察機關", "司法機關不包括檢察機關，警察機關限於組織法上之形式意義警察機關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
