  ('aboriginal-7c9828ae-moex-00055', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-6ed013db', 'sub-aboriginal-7c9828ae-06', NULL, 'single_choice', '關於立法院臨時會召開程序及審議事項，下列敘述何者錯誤？', '["立法院得因立法委員四分之一以上之請求而召開臨時會", "立法院臨時會以決議召集臨時會之特定事項為限", "於立法院休會期間提出不信任案，立法院應即召開臨時會審議之", "立法院於臨時會審議不信任案時，於不信任案提出72小時後，應於48小時內以記名投票表決之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL)
